{
  "family": "Tsuji-Wilkinson Decarbonylation Reaction",
  "candidate": {
    "substrate_smiles": [
      "CCCCCCC=O"
    ],
    "product_smiles": [
      "CCCCCC"
    ],
    "optional_reagent_smiles": [
      "Cl[Rh](P(c1ccccc1)(c1ccccc1)c1ccccc1)(P(c1ccccc1)(c1ccccc1)c1ccccc1)P(c1ccccc1)(c1ccccc1)c1ccccc1"
    ],
    "rationale": "This reaction shows the decarbonylation of a simple, acyclic aliphatic aldehyde (heptanal) to its corresponding alkane (hexane) using Wilkinson's catalyst. This is a classic textbook example that clearly illustrates the C-C bond cleavage of the formyl group and its replacement with a hydrogen atom, which is the core transformation of the Tsuji-Wilkinson decarbonylation.",
    "collision_avoidance_note": "The substrate is a simple aliphatic aldehyde, avoiding aromatic rings which could be confused with other transition-metal catalyzed C-H activation or cross-coupling reactions. The transformation is a straightforward deformylation, distinct from decarboxylation (loss of CO2 from a carboxylic acid) or deoxygenation (e.g., Wolff-Kishner, Clemmensen reductions)."
  }
}
